import{_ as o,o as a,c as n,a3 as i}from"./chunks/framework.CRbjHCyB.js";const u=JSON.parse('{"title":"Source Code Overview","description":"","frontmatter":{},"headers":[],"relativePath":"clice/design/overview.md","filePath":"en/clice/design/overview.md"}'),t={name:"clice/design/overview.md"};function s(r,e,c,l,d,p){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="source-code-overview" tabindex="-1">Source Code Overview <a class="header-anchor" href="#source-code-overview" aria-label="Permalink to &quot;Source Code Overview&quot;">​</a></h1><p>This document describes the responsibilities and role of each module in the clice source tree, providing readers with a high-level understanding of the overall project structure. For detailed design information on each module, refer to the corresponding topic documents.</p><h2 id="project-vision" tabindex="-1">Project Vision <a class="header-anchor" href="#project-vision" aria-label="Permalink to &quot;Project Vision&quot;">​</a></h2><p>clice is a brand-new C++ language server, redesigned from the architecture level to solve long-standing problems in previous C++ language servers. Key features:</p><ul><li><p><strong>Compilation Context</strong>: clice is the first language server to introduce compilation context as a formal concept. Every step of compilation, indexing, and querying explicitly distinguishes the current compilation context, and users can query and switch between them. See <a href="./compilation-context">Compilation Context</a>.</p></li><li><p><strong>Multi-process Architecture</strong>: A master + worker process model isolates Clang&#39;s memory leaks and crashes while enabling priority-aware scheduling and real-time memory monitoring. See <a href="./multi-process">Multi-process Architecture</a>.</p></li><li><p><strong>Coroutine-based Async Model</strong>: Built on C++20 coroutines and the kotatsu library, replacing traditional callback-style async and making business logic clearer.</p></li><li><p><strong>Real-time Module Compilation</strong>: A reference-counted C++20 module compilation DAG with support for real-time cancellation and dependency cascading. See <a href="./module-graph">Module Compilation Graph</a>.</p></li></ul><h2 id="module-overview" tabindex="-1">Module Overview <a class="header-anchor" href="#module-overview" aria-label="Permalink to &quot;Module Overview&quot;">​</a></h2><h3 id="src-support-—-foundation-utility-library" tabindex="-1"><code>src/support/</code> — Foundation Utility Library <a class="header-anchor" href="#src-support-—-foundation-utility-library" aria-label="Permalink to &quot;`src/support/` — Foundation Utility Library&quot;">​</a></h3><p>General-purpose utilities and infrastructure shared by all other modules.</p><ul><li><code>PathPool</code>: Internalizes file paths as <code>uint32_t</code> identifiers, used as stable file identifiers throughout the system</li><li><code>FuzzyMatcher</code>: Token-aware fuzzy matching for code completion and symbol search</li><li>Markup / Doxygen: Parsing and formatting of documentation comments</li><li>Logging, filesystem abstractions, string utilities, etc.</li></ul><h3 id="src-command-—-compilation-command-processing" tabindex="-1"><code>src/command/</code> — Compilation Command Processing <a class="header-anchor" href="#src-command-—-compilation-command-processing" aria-label="Permalink to &quot;`src/command/` — Compilation Command Processing&quot;">​</a></h3><p>Commands read from the compilation database (CDB) are raw commands generated by the build system and cannot be fed directly to the Clang frontend -- they may contain options meant only for code generation, lack system header search paths, or include parameters irrelevant to a language server. This module classifies, filters, probes toolchains, and deduplicates the raw commands, transforming them into compilation parameters consumable by the language server.</p><ul><li><code>CompilationDatabase</code>: Loads <code>compile_commands.json</code> and separates compilation commands into flags that affect semantics (canonical) and flags that only affect user content (patch, such as <code>-I</code> and <code>-D</code>), enabling cross-file command deduplication and sharing</li><li><code>Toolchain</code>: Queries system compilers for complete compilation parameters (such as system header search paths), caching results by (driver, file extension, non-user-content flags)</li><li><code>SearchConfig</code>: A four-tier model for header search paths (Quoted / Angled / System / After), matching Clang&#39;s internal search logic</li></ul><p>See <a href="./command-resolve">Compilation Command Resolution</a>.</p><h3 id="src-compile-—-compilation-abstraction" tabindex="-1"><code>src/compile/</code> — Compilation Abstraction <a class="header-anchor" href="#src-compile-—-compilation-abstraction" aria-label="Permalink to &quot;`src/compile/` — Compilation Abstraction&quot;">​</a></h3><p>Wraps the Clang compiler, abstracting Clang APIs into safe, unified compilation interfaces. This layer is purely a compilation abstraction with no server logic.</p><ul><li><code>CompilationUnit</code> / <code>CompilationUnitRef</code>: RAII wrappers around the Clang AST context. <code>CompilationUnitRef</code> provides a unified read-only view for accessing source location mappings, preprocessor directives, AST nodes, and more. This is the primary input for <code>src/feature/</code> and <code>src/semantic/</code>.</li><li><code>CompilationParams</code>: Describes the complete configuration for a single compilation, including compilation type (Preamble / Content / Completion / Indexing, etc.), file remapping, PCH/PCM reuse, etc.</li></ul><h3 id="src-syntax-—-lightweight-syntax-processing" tabindex="-1"><code>src/syntax/</code> — Lightweight Syntax Processing <a class="header-anchor" href="#src-syntax-—-lightweight-syntax-processing" aria-label="Permalink to &quot;`src/syntax/` — Lightweight Syntax Processing&quot;">​</a></h3><p>Syntax-level processing that does not require a full AST. Runs before compilation to quickly obtain structural information and dependency relationships for files.</p><ul><li><code>Lexer</code>: A token-level utility built on Clang&#39;s raw lexer. Does not run the preprocessor. Used for directive scanning, include path resolution, etc.</li><li><code>DependencyGraph</code>: A global include/module dependency graph supporting forward queries, reverse queries, host source file search, include chain lookup, etc.</li><li>Dependency scanning: Wraps Clang&#39;s <code>DependencyDirectivesScanner</code> to quickly extract include and module dependencies</li><li><code>IncludeResolver</code>: Resolves include paths to actual files based on search path configuration</li></ul><p>See <a href="./dependency-scanning">Dependency Scanning</a>.</p><h3 id="src-semantic-—-semantic-analysis" tabindex="-1"><code>src/semantic/</code> — Semantic Analysis <a class="header-anchor" href="#src-semantic-—-semantic-analysis" aria-label="Permalink to &quot;`src/semantic/` — Semantic Analysis&quot;">​</a></h3><p>Semantic analysis capabilities beyond Clang&#39;s native APIs. Takes a <code>CompilationUnitRef</code> and extracts higher-level semantic information.</p><ul><li><code>SemanticVisitor</code>: An AST traverser that records each symbol&#39;s occurrence location and relations (definition, reference, inheritance, call, etc.). This is the primary producer of index data.</li><li><code>TemplateResolver</code>: Resolves dependent names through pseudo-instantiation, enabling semantic analysis to see through template contexts. See <a href="./template-resolver">Template Resolver</a>.</li><li><code>SymbolKind</code> / <code>RelationKind</code>: Fine-grained symbol kinds and relation types</li></ul><h3 id="src-index-—-symbol-index" tabindex="-1"><code>src/index/</code> — Symbol Index <a class="header-anchor" href="#src-index-—-symbol-index" aria-label="Permalink to &quot;`src/index/` — Symbol Index&quot;">​</a></h3><p>Symbol indexing system with cross-translation-unit query support. Uses a three-tier structure:</p><ul><li><code>TUIndex</code>: Index data produced from a single compilation, generated by <code>SemanticVisitor</code></li><li><code>ProjectIndex</code>: The global symbol table. Aggregates symbol information from all indexed files, supporting lookup by symbol hash</li><li><code>MergedIndex</code>: Per-file sharded index storage. Merges index data produced from the same file under different compilation contexts</li></ul><p>See <a href="./symbol-index">Symbol Index</a>.</p><h3 id="src-feature-—-lsp-feature-implementations" tabindex="-1"><code>src/feature/</code> — LSP Feature Implementations <a class="header-anchor" href="#src-feature-—-lsp-feature-implementations" aria-label="Permalink to &quot;`src/feature/` — LSP Feature Implementations&quot;">​</a></h3><p>Concrete implementations of LSP features. Each feature takes a <code>CompilationUnitRef</code> and returns the corresponding LSP response data. This layer is purely computational -- it has no involvement with network communication, state management, or process scheduling.</p><p>Includes: code completion, hover information, signature help, semantic highlighting, inlay hints, document symbols, document links, folding ranges, formatting, diagnostics, etc.</p><blockquote><p><code>feature/</code> only covers single-file, AST-based feature implementations. Cross-file navigation features (go to definition, find references, etc.) are handled by the <code>Indexer</code> using index data. Some features involve multi-phase processing -- for example, include path completion in code completion can be resolved at the syntax layer without full compilation.</p></blockquote><h3 id="src-server-—-server-runtime" tabindex="-1"><code>src/server/</code> — Server Runtime <a class="header-anchor" href="#src-server-—-server-runtime" aria-label="Permalink to &quot;`src/server/` — Server Runtime&quot;">​</a></h3><p>The language server&#39;s core runtime, responsible for assembling all the layers above into a runnable service.</p><p><strong><code>protocol/</code></strong> — Protocol definitions. Describes the message formats for communication between the master process and worker processes, as well as between the server and clients. Includes Worker protocol (compilation/query/build requests), LSP extension protocol (compilation context switching, etc.), and the agentic protocol for AI agents.</p><p><strong><code>workspace/</code></strong> — Project-level global state. <code>Workspace</code> holds the compilation database, toolchain, path pool, dependency graph, PCH/PCM cache, project index, and all other project-level state. Core invariant: unsaved buffer contents of open files never modify the <code>Workspace</code> -- it only reflects the state on disk.</p><p><strong><code>compiler/</code></strong> — Compilation scheduling and index management.</p><ul><li><code>Compiler</code>: The scheduler for compilation lifecycles. Coordinates the ordering of PCH builds, module dependency resolution, and AST compilation, dispatching compilation tasks to worker processes</li><li><code>CompileGraph</code>: The DAG scheduler for C++20 module compilation. Uses reference counting for interest tracking, supporting dependency cascade cancellation</li><li><code>Indexer</code>: Handles background indexing scheduling and serves as the entry point for cross-file queries. Combines <code>ProjectIndex</code>, <code>MergedIndex</code>, and in-memory indexes for open files to provide query results</li></ul><p><strong><code>service/</code></strong> — Service entry point and session management.</p><ul><li><code>MasterServer</code>: The top-level coordinator. Holds <code>Workspace</code>, <code>Session</code> map, <code>WorkerPool</code>, <code>Compiler</code>, and <code>Indexer</code>, routing LSP requests to the appropriate handling logic</li><li><code>Session</code>: The editing state for each open file (buffer contents, compilation version number, in-memory index, PCH reference, etc.). Created on didOpen, destroyed on didClose</li><li><code>LSPClient</code> / <code>AgentClient</code>: Request handlers for the LSP protocol and agentic protocol</li></ul><p><strong><code>worker/</code></strong> — Worker process management.</p><ul><li><code>WorkerPool</code>: Manages worker process lifecycles and scheduling. Stateful workers (<code>StatefulWorker</code>) hold AST and serve query requests. Stateless workers (<code>StatelessWorker</code>) execute one-shot tasks (PCH/PCM builds, completion, indexing, etc.)</li><li>Process fault tolerance: Workers are automatically restarted on crash. When a stateful worker crashes, its owned documents are automatically reassigned</li></ul><p>See <a href="./multi-process">Multi-process Architecture</a>.</p><h2 id="inter-module-relationships" tabindex="-1">Inter-module Relationships <a class="header-anchor" href="#inter-module-relationships" aria-label="Permalink to &quot;Inter-module Relationships&quot;">​</a></h2><p>The data flow roughly follows this direction:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>command (compilation command parsing)</span></span>\n<span class="line"><span>    ↓</span></span>\n<span class="line"><span>compile (drives Clang compilation)</span></span>\n<span class="line"><span>    ↓</span></span>\n<span class="line"><span>semantic (extracts semantic information) ──→ index (builds indexes)</span></span>\n<span class="line"><span>    ↓</span></span>\n<span class="line"><span>feature (produces LSP responses)</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>The server layer assembles all of the above via Workspace / Session / WorkerPool into a runnable service</span></span></code></pre></div><p><code>support</code> and <code>syntax</code> are cross-cutting layers shared by multiple modules.</p>',46)])])}const h=o(t,[["render",s]]);export{u as __pageData,h as default};
